import { useEffect, useReducer, useRef, useState } from 'react';
import { trapFocus } from '../a11y/trap-focus';
import { computeClues, makeBoard } from '../../engine';
import { verifyUniqueAsync, verifyUniqueDeductiveAsync } from '../../engine/verifier-client';
import { useGameActions, useStore } from '../../state/store';
import './builder.css';

interface Props { onClose: () => void; }

const SIZE = 10;       // 10×10 builder (matches "beginner")
const TOTAL = SIZE * SIZE;

function emptySolution(): (0 | 1)[] { return new Array(TOTAL).fill(0); }

function encodeHash(sol: (0 | 1)[]): string {
  // Pack 1 cell/bit into base36-ish: 25 bytes for 100 bits → encode as URL-safe.
  let s = '';
  for (let i = 0; i < sol.length; i += 4) {
    const a = sol[i] ?? 0, b = sol[i + 1] ?? 0, c = sol[i + 2] ?? 0, d = sol[i + 3] ?? 0;
    const nibble = (a << 3) | (b << 2) | (c << 1) | d;
    s += nibble.toString(16);
  }
  return s;
}

function decodeHash(s: string): (0 | 1)[] | null {
  if (s.length !== TOTAL / 4) return null;
  const out: (0 | 1)[] = [];
  for (let i = 0; i < s.length; i++) {
    const ch = s[i] ?? '';
    if (!/[0-9a-f]/.test(ch)) return null;
    const n = parseInt(ch, 16);
    out.push(((n >> 3) & 1) as 0 | 1);
    out.push(((n >> 2) & 1) as 0 | 1);
    out.push(((n >> 1) & 1) as 0 | 1);
    out.push((n & 1) as 0 | 1);
  }
  return out.length === TOTAL ? out : null;
}

interface Validation {
  status: 'idle' | 'ok' | 'fail';
  msg?: string;
}

export function BuilderSheet({ onClose }: Props) {
  const ref = useRef<HTMLDivElement>(null);
  const a = useGameActions();
  const [, force] = useReducer(x => x + 1, 0);
  const [sol, setSol] = useState<(0 | 1)[]>(() => {
    // If URL has ?b=... at mount, prefill.
    try {
      const u = new URL(window.location.href);
      const b = u.searchParams.get('b');
      if (b) {
        const d = decodeHash(b);
        if (d) return d;
      }
    } catch {}
    return emptySolution();
  });
  const [v, setV] = useState<Validation>({ status: 'idle' });
  const [copied, setCopied] = useState(false);

  useEffect(() => {
    const node = ref.current;
    if (!node) return;
    const release = trapFocus(node);
    function onKey(e: KeyboardEvent) { if (e.key === 'Escape') onClose(); }
    window.addEventListener('keydown', onKey);
    return () => { release(); window.removeEventListener('keydown', onKey); };
  }, [onClose]);

  function toggle(i: number) {
    const next = sol.slice();
    next[i] = (next[i] === 1 ? 0 : 1);
    setSol(next);
    setV({ status: 'idle' });
  }
  function clear() {
    setSol(emptySolution());
    setV({ status: 'idle' });
  }
  function fillAll() {
    const next: (0 | 1)[] = new Array(TOTAL).fill(1);
    setSol(next);
    setV({ status: 'idle' });
  }

  // Validate: build clues from solution, then check (a) backtracking confirms
  // uniqueness AND (b) line-solver alone reaches a full solution.
  //
  // Both steps now run in a Web Worker (with an inline fallback) so the main
  // thread stays at 60 fps during validation. Worst-case 10×10 used to block
  // ~120 ms; now zero main-thread cost beyond the message hop.
  //
  // Time complexity: O(N^3) worst-case for backtracking on a 10×10 — typically <50 ms
  // on the worker thread.
  async function validate() {
    if (sol.every(c => c === 0)) {
      setV({ status: 'fail', msg: 'Empty puzzle — fill at least one cell.' });
      return;
    }
    const clues = computeClues(sol, SIZE, SIZE);
    if (clues.rows.some(r => r.length === 0) || clues.cols.some(c => c.length === 0)) {
      setV({ status: 'fail', msg: 'Each row and column needs at least one clue.' });
      return;
    }
    setV({ status: 'idle', msg: 'Validating…' });
    try {
      const unique = await verifyUniqueAsync(clues, SIZE, SIZE);
      if (!unique) {
        setV({ status: 'fail', msg: 'Multiple solutions — your puzzle is ambiguous.' });
        return;
      }
      const deductive = await verifyUniqueDeductiveAsync(sol, SIZE, SIZE);
      const note = deductive ? 'fully deductive' : 'requires lookahead but unique';
      setV({ status: 'ok', msg: `Looks good — ${note}.` });
    } catch {
      setV({ status: 'fail', msg: 'Validation failed — try again.' });
    }
  }

  async function copyShareLink() {
    const hash = encodeHash(sol);
    const u = new URL(window.location.href);
    u.searchParams.set('b', hash);
    try {
      await navigator.clipboard.writeText(u.toString());
      setCopied(true);
      setTimeout(() => setCopied(false), 1800);
    } catch {}
  }

  function playIt() {
    if (v.status !== 'ok') return;
    // Drop the user into a free-play game with this custom solution.
    const board = makeBoard(sol, SIZE, SIZE);
    useStore.setState({
      board, size: 'beginner', mode: 'free',
      startedAt: Date.now(), timeMs: 0,
      paused: false, solved: false, revealed: false,
      mistakes: 0, softFailed: false, hintsUsed: 0,
      primary: 'fill',
      hover: null, dragInProgress: false,
      undoStack: [], redoStack: [],
      gameStartCount: useStore.getState().gameStartCount + 1,
    });
    onClose();
    void a; void force;
  }

  const filled = sol.reduce<number>((s, c) => s + c, 0);

  return (
    <div className="etch-build-backdrop" role="dialog" aria-modal="true" aria-label="Custom puzzle builder" onClick={onClose}>
      <div className="etch-build-sheet" ref={ref} onClick={(e) => e.stopPropagation()}>
        <header>
          <h2>Custom puzzle</h2>
          <button className="etch-build-close" aria-label="Close" onClick={onClose}>×</button>
        </header>
        <p className="etch-build-hint">
          Tap cells to design your own 10×10 nonogram. Validate to confirm it has a unique solution.
        </p>
        <div className="etch-build-grid" role="grid" aria-label="Builder grid">
          {Array.from({ length: SIZE }, (_, r) => (
            <div role="row" key={r} style={{ display: 'contents' }}>
              {Array.from({ length: SIZE }, (_, col) => {
                const i = r * SIZE + col;
                const on = sol[i] === 1;
                return (
                  <button
                    role="gridcell"
                    aria-rowindex={r + 1}
                    aria-colindex={col + 1}
                    aria-pressed={on}
                    aria-label={`Row ${r + 1} column ${col + 1}`}
                    key={col}
                    type="button"
                    className={`etch-build-cell${on ? ' is-on' : ''}`}
                    data-r={r}
                    data-c={col}
                    onClick={() => toggle(i)}
                  />
                );
              })}
            </div>
          ))}
        </div>
        <div className="etch-build-meta">
          <span>{filled} cells filled</span>
          {v.status !== 'idle' && (
            <span
              role="status"
              className={`etch-build-status etch-build-status-${v.status}`}
            >
              {v.msg}
            </span>
          )}
        </div>
        <div className="etch-build-actions">
          <button type="button" onClick={clear} className="etch-build-btn etch-build-btn-ghost">Clear</button>
          <button type="button" onClick={fillAll} className="etch-build-btn etch-build-btn-ghost">Fill all</button>
          <button type="button" onClick={() => void validate()} className="etch-build-btn etch-build-btn-ghost">Validate</button>
          <button
            type="button"
            onClick={() => void copyShareLink()}
            className="etch-build-btn etch-build-btn-ghost"
            disabled={filled === 0}
          >
            {copied ? 'Copied!' : 'Share link'}
          </button>
          <button
            type="button"
            onClick={playIt}
            disabled={v.status !== 'ok'}
            className="etch-build-btn etch-build-btn-primary"
          >
            Play
          </button>
        </div>
      </div>
    </div>
  );
}

export default BuilderSheet;
