/**
 * verifier-client.ts — Promise-based client for the verifier worker.
 *
 * Workers run user code off the main thread, freeing the UI to repaint at
 * 60 fps while we backtrack through ambiguous puzzles. We keep one
 * singleton worker for the lifetime of the tab; it's lightweight enough
 * not to need teardown.
 *
 * If `Worker` is unavailable (Node tests, very old WebViews, SSR), we fall
 * back to the inline synchronous implementation. The caller's API stays
 * Promise-based either way.
 *
 * Time complexity: O(1) overhead per call; the solver itself is the
 * dominant cost. Space: O(1) — one worker instance, no message backlog.
 */
import type { Clues } from './types';
import { verifyUnique as verifyUniqueInline, verifyUniqueDeductive as verifyUniqueDeductiveInline } from './verifier';

interface WorkerOut {
  id: number;
  ok: boolean;
  result?: boolean;
  error?: string;
}

let worker: Worker | null = null;
let nextId = 1;
const pending = new Map<number, { resolve: (v: boolean) => void; reject: (e: Error) => void }>();

function getWorker(): Worker | null {
  if (typeof Worker === 'undefined') return null;
  if (worker) return worker;
  try {
    // Vite resolves `new URL(..., import.meta.url)` to the worker chunk URL.
    worker = new Worker(new URL('./verifier.worker.ts', import.meta.url), { type: 'module' });
    worker.addEventListener('message', (e: MessageEvent<WorkerOut>) => {
      const { id, ok, result, error } = e.data;
      const entry = pending.get(id);
      if (!entry) return;
      pending.delete(id);
      if (ok && typeof result === 'boolean') entry.resolve(result);
      else entry.reject(new Error(error ?? 'worker error'));
    });
    worker.addEventListener('error', () => {
      // Bail every pending call so we don't hang the UI.
      for (const { reject } of pending.values()) reject(new Error('worker crashed'));
      pending.clear();
      worker = null;
    });
    return worker;
  } catch {
    worker = null;
    return null;
  }
}

function call(kind: 'verifyUnique' | 'verifyUniqueDeductive', payload: Record<string, unknown>): Promise<boolean> {
  const w = getWorker();
  if (!w) {
    // Inline fallback — synchronous path, but we return a Promise to match
    // the contract.
    try {
      const r = kind === 'verifyUnique'
        ? verifyUniqueInline(payload['clues'] as Clues, payload['w'] as number, payload['h'] as number)
        : verifyUniqueDeductiveInline(payload['solution'] as (0 | 1)[], payload['w'] as number, payload['h'] as number);
      return Promise.resolve(r);
    } catch (err) {
      return Promise.reject(err instanceof Error ? err : new Error(String(err)));
    }
  }
  const id = nextId++;
  return new Promise<boolean>((resolve, reject) => {
    pending.set(id, { resolve, reject });
    w.postMessage({ id, kind, ...payload });
  });
}

export function verifyUniqueAsync(clues: Clues, w: number, h: number): Promise<boolean> {
  return call('verifyUnique', { clues, w, h });
}

export function verifyUniqueDeductiveAsync(solution: (0 | 1)[], w: number, h: number): Promise<boolean> {
  return call('verifyUniqueDeductive', { solution, w, h });
}

/** Test-only: reset the singleton (used to exercise the fallback path). */
export function __resetVerifierClient(): void {
  if (worker) {
    try { worker.terminate(); } catch {}
  }
  worker = null;
  pending.clear();
}
